SELECT s.year, s.month, SUM(s.shipped_units) AS total_shipped, SUM(COALESCE(c.conceded_units, 0)) AS total_conceded, (SUM(c.conceded_units) * 100.0) / NULLIF(SUM(s.shipped_units), 0) AS return_rate_pct FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.item_name ILIKE '%iphone%' GROUP BY s.year, s.month ORDER BY s.year, s.month;